.home-parent-container{
    position: relative;
    display: flex;
    justify-content: flex-start;
    align-items: center;
    position: relative;
    width: 100%;
    height: 100vh;
    overflow-y: auto;
    overflow-x: hidden;  
}
.uploading-bg{
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: var(--bg-overlay);
    backdrop-filter: blur(25px);
    width: 100%;
    height:100vh;
    z-index: 11;
}
.newsfeed-header{
    position: fixed;
    display: none;
    background-color: var(--bg-backdrop);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(5px);
    justify-content: space-evenly;
    align-items: center;
    width: 750px;
    height: 90px;
    border-bottom: 0.7px solid var(--border-light);
    z-index: 120;
}
.header-links{
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
}
.header-link{
    display: flex;
    justify-content: center;
    align-items: center;
    position: relative;
    flex-direction: column;
}
.header-underline{
    width: 100%;
    height: 6px;
    border-radius: 5px;
    background-color: #a2daff;
    transition: ease-in-out 0.2;
}

