    font-weight: 600;
    letter-spacing: 0.02em;
    opacity: 0.5;
    cursor: default;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}
.profile-edit-container{
    position: relative;
    display: flex;
    justify-content: center;
    height: fit-content;
    width: 100%;
}
.profile-edit-backdrop-filter{
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100px;
    height: 100px;
    border-radius: 50%;
    background-color: rgba(0, 0, 0, 0.35);
}
.profile-img-edit-preview{
    width: 100px;
    height: 100px;
    border-radius: 50%;
