    display: flex;
    justify-content: center;
    height: fit-content;
    width: 100%;
}
.profile-edit-backdrop-filter{
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100px;
    height: 100px;
    border-radius: 50%;
    background-color: rgba(0, 0, 0, 0.35);
}
.profile-img-edit-preview{
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
}
.camera-icon-container{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem;
    border-radius: 50%;
    background-color: rgba(0, 0, 0, 0.5);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    cursor: pointer;
    transition: background-color 0.2s ease;
}
.camera-icon-container:hover{
    background-color: rgba(0, 0, 0, 0.3);
}
.profile-edit-metadata-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: stretch;
    gap: 16px;
    width: 100%;
}
.input-title{
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 600;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    color: var(--text-muted);
}
.name-input-container{
    display: flex;
    width: 100%;
    flex-direction: column;
    gap: 6px;
    box-sizing: border-box;
}
.edit-profile-name-input{
    font-family: var(--font-ui);
    width: 100%;
    border: 1px solid var(--border-card);
    background: var(--bg-primary);
    padding: 14px 16px;
    border-radius: 8px;
    font-size: 0.95rem;
    color: var(--text-primary);
    box-sizing: border-box;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
    outline: none;
}
.edit-profile-name-input:focus{
    border-color: var(--accent-amber);
    box-shadow: 0 0 0 3px rgba(212, 168, 83, 0.12);
}
.edit-profile-name-input::placeholder{
    color: var(--text-faint);
}
.bio-input-container{
    display: flex;
    width: 100%;
    flex-direction: column;
    gap: 6px;
    box-sizing: border-box;
}
.edit-profile-bio-input{
    font-family: var(--font-ui);
    width: 100%;
    border: 1px solid var(--border-card);
    background: var(--bg-primary);
    padding: 14px 16px;
    border-radius: 8px;
    font-size: 0.95rem;
    color: var(--text-primary);
    box-sizing: border-box;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
    outline: none;
    resize: none;
    height: 100px;
}
.edit-profile-bio-input:focus{
    border-color: var(--accent-amber);
    box-shadow: 0 0 0 3px rgba(212, 168, 83, 0.12);
}
.edit-profile-bio-input::placeholder{
    color: var(--text-faint);
}
.input-title-container{
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.username-status-available{
    color: var(--color-success);
}
.username-status-taken{
    color: var(--color-danger);
}
.username-status-checking{
    color: var(--text-muted);
}
