mobile responsive */

@media (max-width: 768px){
    .side-bar-holder-container{
        position: fixed;
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 200px;
        height: 100%;
        border-right: 0.7px solid var(--border-light);
